def generate_proto_files():
    """Generate Python gRPC code from proto definition."""
    proto_dir = os.path.dirname(os.path.abspath(__file__))
    proto_file = os.path.join(proto_dir, "service.proto")

    with open(proto_file, "w") as f:
        f.write(PROTO_CONTENT)

    cmd = [
        sys.executable, "-m", "grpc_tools.protoc",
        f"--proto_path={proto_dir}",
        f"--python_out={proto_dir}",
        f"--grpc_python_out={proto_dir}",
        proto_file
    ]

    try:
        subprocess.run(cmd, check=True, capture_output=True, text=True)
        print("Proto files generated successfully!")
        return True
    except subprocess.CalledProcessError as e:
        print(f"Error generating proto files: {e.stderr}")
        return False
    except FileNotFoundError:
        print("grpcio-tools not found. Install with: pip install grpcio-tools")
        return False


