import uuid
import time
import hashlib
import json
import threading
from concurrent import futures
from dataclasses import dataclass, field, asdict
from typing import Dict, Optional


@dataclass
class User:
    user_id: str
    username: str
    email: str
    full_name: str
    password_hash: str
    created_at: int


@dataclass
class Session:
    token: str
    user_id: str
    username: str
    created_at: int
    expires_at: int


class InMemoryDB:
    """Thread-safe in-memory database for development."""

    def __init__(self):
        self._users: Dict[str, User] = {}
        self._usernames: Dict[str, str] = {}  # username -> user_id
        self._sessions: Dict[str, Session] = {}  # token -> Session
        self._lock = threading.RLock()
        self._seed_data()

    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def _seed_data(self):
        """Seed with initial test data."""
        test_users = [
            ("admin", "admin@example.com", "Admin User", "admin123"),
            ("johndoe", "john@example.com", "John Doe", "password123"),
            ("janedoe", "jane@example.com", "Jane Doe", "password456"),
        ]
        for username, email, full_name, password in test_users:
            user_id = str(uuid.uuid4())
            user = User(
                user_id=user_id,
                username=username,
                email=email,
                full_name=full_name,
                password_hash=self._hash_password(password),
                created_at=int(time.time())
            )
            self._users[user_id] = user
            self._usernames[username] = user_id

    def register_user(self, username: str, email: str, full_name: str, password: str) -> Optional[User]:
        with self._lock:
            if username in self._usernames:
                return None
            user_id = str(uuid.uuid4())
            user = User(
                user_id=user_id,
                username=username,
                email=email,
                full_name=full_name,
                password_hash=self._hash_password(password),
                created_at=int(time.time())
            )
            self._users[user_id] = user
            self._usernames[username] = user_id
            return user

    def authenticate(self, username: str, password: str) -> Optional[User]:
        with self._lock:
            user_id = self._usernames.get(username)
            if not user_id:
                return None
            user = self._users[user_id]
            if user.password_hash == self._hash_password(password):
                return user
            return None

    def create_session(self, user: User) -> Session:
        with self._lock:
            token = str(uuid.uuid4())
            now = int(time.time())
            session = Session(
                token=token,
                user_id=user.user_id,
                username=user.username,
                created_at=now,
                expires_at=now + 3600  # 1 hour
            )
            self._sessions[token] = session
            return session

    def validate_session(self, token: str) -> Optional[Session]:
        with self._lock:
            session = self._sessions.get(token)
            if session and session.expires_at > int(time.time()):
                return session
            if session:
                del self._sessions[token]
            return None

    def invalidate_session(self, token: str) -> bool:
        with self._lock:
            if token in self._sessions:
                del self._sessions[token]
                return True
            return False

    def get_user(self, user_id: str) -> Optional[User]:
        with self._lock:
            return self._users.get(user_id)

    def list_users(self, page: int = 1, page_size: int = 10):
        with self._lock:
            users = list(self._users.values())
            total = len(users)
            start = (page - 1) * page_size
            end = start + page_size
            return users[start:end], total


# Global database instance
db = InMemoryDB()


