import grpc
from concurrent import futures
import logging

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger("grpc_server")


# Since we generate proto files dynamically, we'll define the servicer
# classes that work with generated code, but also provide a standalone
# implementation that can work without proto generation.

class AuthServiceServicer:
    """Implementation of the AuthService."""

    def Login(self, request, context):
        """Handle user login."""
        logger.info(f"Login attempt for user: {request.username}")

        user = db.authenticate(request.username, request.password)
        if not user:
            # We need to import the generated module
            import service_pb2
            return service_pb2.LoginResponse(
                success=False,
                token="",
                message="Invalid username or password"
            )

        session = db.create_session(user)
        import service_pb2
        user_info = service_pb2.UserInfo(
            user_id=user.user_id,
            username=user.username,
            email=user.email,
            full_name=user.full_name,
            created_at=user.created_at
        )

        logger.info(f"User {request.username} logged in successfully")
        return service_pb2.LoginResponse(
            success=True,
            token=session.token,
            message="Login successful",
            user=user_info
        )

    def Register(self, request, context):
        """Handle user registration."""
        logger.info(f"Registration attempt for user: {request.username}")

        import service_pb2

        if not request.username or not request.password or not request.email:
            return service_pb2.RegisterResponse(
                success=False,
                message="Username, email, and password are required",
                user_id=""
            )

        user = db.register_user(
            username=request.username,
            email=request.email,
            full_name=request.full_name,
            password=request.password
        )

        if not user:
            return service_pb2.RegisterResponse(
                success=False,
                message="Username already exists",
                user_id=""
            )

        logger.info(f"User {request.username} registered successfully")
        return service_pb2.RegisterResponse(
            success=True,
            message="Registration successful",
            user_id=user.user_id
        )

    def ValidateToken(self, request, context):
        """Validate an authentication token."""
        import service_pb2

        session = db.validate_session(request.token)
        if not session:
            return service_pb2.TokenResponse(
                valid=False,
                user_id="",
                username="",
                expires_at=0
            )

        return service_pb2.TokenResponse(
            valid=True,
            user_id=session.user_id,
            username=session.username,
            expires_at=session.expires_at
        )

    def Logout(self, request, context):
        """Handle user logout."""
        import service_pb2

        success = db.invalidate_session(request.token)
        return service_pb2.LogoutResponse(
            success=success,
            message="Logged out successfully" if success else "Invalid token"
        )


class DataServiceServicer:
    """Implementation of the DataService."""

    def _validate_token(self, token, context):
        """Helper to validate token and set error if invalid."""
        session = db.validate_session(token)
        if not session:
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid or expired token")
            return None
        return session

    def GetUser(self, request, context):
        """Get a single user by ID."""
        import service_pb2

        session = self._validate_token(request.token, context)
        if not session:
            return service_pb2.UserResponse(
                success=False,
                message="Authentication required"
            )

        user = db.get_user(request.user_id)
        if not user:
            return service_pb2.UserResponse(
                success=False,
                message="User not found"
            )

        user_info = service_pb2.UserInfo(
            user_id=user.user_id,
            username=user.username,
            email=user.email,
            full_name=user.full_name,
            created_at=user.created_at
        )

        return service_pb2.UserResponse(
            success=True,
            user=user_info,
            message="User retrieved successfully"
        )

    def ListUsers(self, request, context):
        """List users with pagination."""
        import service_pb2

        session = self._validate_token(request.token, context)
        if not session:
            return service_pb2.ListUsersResponse(
                success=False,
                message="Authentication required"
            )

        page = max(request.page, 1)
        page_size = min(max(request.page_size, 1), 100)

        users, total_count = db.list_users(page, page_size)

        user_infos = [
            service_pb2.UserInfo(
                user_id=u.user_id,
                username=u.username,
                email=u.email,
                full_name=u.full_name,
                created_at=u.created_at
            )
            for u in users
        ]

        return service_pb2.ListUsersResponse(
            success=True,
            users=user_infos,
            total_count=total_count,
            message=f"Retrieved {len(user_infos)} users"
        )

    def GetData(self, request, context):
        """Get generic data resource."""
        import service_pb2

        session = self._validate_token(request.token, context)
        if not session:
            return service_pb2.DataResponse(
                success=False,
                message="Authentication required"
            )

        # Simulate data retrieval based on resource type
        resource_data = {
            "settings": {
                "theme": "dark",
                "language": "en",
                "notifications": True,
                "timezone": "UTC"
            },
            "stats": {
                "total_users": len(db._users),
                "active_sessions": len(db._sessions),
                "uptime_seconds": int(time.time()) % 86400
            },
            "profile": None  # Will be populated dynamically
        }

        if request.resource_type == "profile":
            user = db.get_user(session.user_id)
            if user:
                resource_data["profile"] = {
                    "user_id": user.user_id,
                    "username": user.username,
                    "email": user.email,
                    "full_name": user.full_name,
                    "member_since": user.created_at
                }

        data = resource_data.get(request.resource_type)
        if data is None:
            return service_pb2.DataResponse(
                success=False,
                data_json="",
                message=f"Unknown resource type: {request.resource_type}"
            )

        # Apply filters if any
        if request.filters and isinstance(data, dict):
            filtered_data = {}
            filter_keys = set(request.filters.keys())
            for key, value in data.items():
                if not filter_keys or key in filter_keys:
                    filtered_data[key] = value
            data = filtered_data

        return service_pb2.DataResponse(
            success=True,
            data_json=json.dumps(data, indent=2),
            message="Data retrieved successfully"
        )

    def StreamData(self, request, context):
        """Stream data in chunks (server-side streaming)."""
        import service_pb2

        session = self._validate_token(request.token, context)
        if not session:
            return

        logger.info(f"Streaming data for resource: {request.resource_type}")

        # Simulate streaming large dataset
        sample_data = []
        for i in range(50):
            sample_data.append({
                "id": i,
                "resource_type": request.resource_type,
                "timestamp": int(time.time()) + i,
                "value": f"data_item_{i}",
                "metadata": {"source": "stream", "index": i}
            })

        # Split into chunks
        chunk_size = 10
        chunks = [sample_data[i:i + chunk_size] for i in range(0, len(sample_data), chunk_size)]
        total_chunks = len(chunks)

        for idx, chunk in enumerate(chunks):
            chunk_bytes = json.dumps(chunk).encode('utf-8')
            yield service_pb2.DataChunk(
                chunk_data=chunk_bytes,
                chunk_index=idx,
                total_chunks=total_chunks,
                is_last=(idx == total_chunks - 1)
            )
            time.sleep(0.1)  # Simulate processing delay

        logger.info(f"Streaming complete: {total_chunks} chunks sent")


class GRPCServer:
    """gRPC Server manager."""

    def __init__(self, host="0.0.0.0", port=50051, max_workers=10):
        self.host = host
        self.port = port
        self.max_workers = max_workers
        self.server = None

    def start(self):
        """Start the gRPC server."""
        import service_pb2_grpc

        self.server = grpc.server(
            futures.ThreadPoolExecutor(max_workers=self.max_workers),
            options=[
                ('grpc.max_send_message_length', 50 * 1024 * 1024),
                ('grpc.max_receive_message_length', 50 * 1024 * 1024),
                ('grpc.keepalive_time_ms', 30000),
                ('grpc.keepalive_timeout_ms', 5000),
                ('grpc.keepalive_permit_without_calls', True),
                ('grpc.http2.max_pings_without_data', 0),
                ('grpc.http2.min_time_between_pings_ms', 10000),
            ]
        )

        # Register services
        service_pb2_grpc.add_AuthServiceServicer_to_server(
            AuthServiceServicer(), self.server
        )
        service_pb2_grpc.add_DataServiceServicer_to_server(
            DataServiceServicer(), self.server
        )

        # Bind to port
        bind_address = f"{self.host}:{self.port}"
        self.server.add_insecure_port(bind_address)

        self.server.start()
        logger.info(f"gRPC Server started on {bind_address}")
        logger.info(f"Max workers: {self.max_workers}")
        logger.info("Services registered: AuthService, DataService")
        logger.info("Press Ctrl+C to stop the server")

        return self.server

    def stop(self, grace=5):
        """Stop the gRPC server."""
        if self.server:
            self.server.stop(grace)
            logger.info("gRPC Server stopped")

    def wait_for_termination(self):
        """Block until the server terminates."""
        if self.server:
            self.server.wait_for_termination()


