# Health check interceptor
# ============================================================

class LoggingInterceptor(grpc.ServerInterceptor):
    """Server interceptor for logging requests."""

    def intercept_service(self, continuation, handler_call_details):
        logger.info(f"Request: {handler_call_details.method}")
        return continuation(handler_call_details)


# ============================================================
# Main execution
# ============================================================

def run_server():
    """Run the gRPC server."""
    server = GRPCServer(host="0.0.0.0", port=50051, max_workers=10)
    server.start()

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        server.stop(grace=5)


def run_client_demo():
    """Run the client demo."""
    print("=" * 60)
    print("gRPC Microservices Client Demo")
    print("=" * 60)

    with MicroservicesClient(host="localhost", port=50051) as client:
        # 1. Register a new user
        print("\n--- Register New User ---")
        reg_response = client.register(
            username="newuser",
            email="newuser@example.com",
            password="securepass123",
            full_name="New User"
        )

        # 2. Login
        print("\n--- Login ---")
        login_response = client.login("admin", "admin123")

        if not login_response or not login_response.success:
            print("Login failed. Exiting.")
            return

        # 3. Validate Token
        print("\n--- Validate Token ---")
        client.validate_token()

        # 4. List Users
        print("\n--- List Users ---")
        client.list_users(page=1, page_size=10)

        # 5. Get User
        if login_response.user:
            print("\n--- Get User ---")
            client.get_user(login_response.user.user_id)

        # 6. Get Data - Settings
        print("\n--- Get Settings Data ---")
        client.get_data("settings")

        # 7. Get Data - Stats
        print("\n--- Get Stats Data ---")
        client.get_data("stats")

        # 8. Get Data - Profile
        print("\n--- Get Profile Data ---")
        client.get_data("profile")

        # 9. Stream Data
        print("\n--- Stream Data ---")
        client.stream_data("events")

        # 10. Logout
        print("\n--- Logout ---")
        client.logout()

        # 11. Try to access data after logout
        print("\n--- Access After Logout (should fail) ---")
        client.list_users()

    print("\n" + "=" * 60)
    print("Demo complete!")
    print("=" * 60)


if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="gRPC Microservices")
    parser.add_argument(
        "mode",
        choices=["generate", "server", "client"],
        help="Mode: 'generate' proto files, run 'server', or run 'client' demo"
    )
    parser.add_argument("--host", default="localhost", help="Server host")
    parser.add_argument("--port", type=int, default=50051, help="Server port")

    args = parser.parse_args()

    if args.mode == "generate":
        generate_proto_files()
    elif args.mode == "server":
        run_server()
    elif args.mode == "client":
        run_client_demo()